/**
 * Checks if a given GitHub username has forked the NUTTER-XMD repo
 * @summary Verify GitHub fork
 */
export const getVerifyForkUrl = (params: VerifyForkParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/deploy/verify-fork?${stringifiedParams}`
    : `/api/deploy/verify-fork`;
};

